pub fn parallel_increment(counter: &std::sync::atomic::AtomicUsize, threads: usize, per_thread: usize) -> usize {
    use std::thread;

    let mut handles = Vec::with_capacity(threads);

    for _ in 0..threads {
        let counter = counter; // Clone reference (AtomicUsize is Copy)
        handles.push(thread::spawn(move || {
            for _ in 0..per_thread {
                counter.fetch_add(1, Ordering::Relaxed);
            }
        }));
    }

    for handle in handles {
        handle.join().unwrap();
    }

    counter.load(Ordering::Relaxed)
}

